+                var label = _stepLabels[step];
+                var isCurrent = step == _currentStep;
+                var isCompleted = step < _highestCompletedStep || _submitted;
+                var isClickable = isCompleted && !_submitted;
+
+                <div class="step-item text-center @(isCurrent ? "active" : "") @(isCompleted ? "completed" : "") @(step > _highestCompletedStep && !_submitted ? "dimmed" : "")"
+                     @onclick="() => { if (isClickable) GoToStep(step); }"
+                     role="@(isClickable ? "button" : "")"
+                     style="@(isClickable ? "cursor: pointer;" : "")">
+                    <div class="step-circle">
+                        @if (isCompleted)
+                        {
+                            <span>&#10003;</span>
+                        }
+                        else
+                        {
+                            <span>@(step + 1)</span>
+                        }
+                    </div>
+                    <div class="step-label mt-1 small">@label</div>
+                </div>
+            }
+        </div>
+    </nav>
+
+    @if (!string.IsNullOrEmpty(_errorMessage))
+    {
+        <div class="alert alert-danger alert-dismissible" role="alert">
+            @_errorMessage
+            <button type="button" class="btn-close" @onclick="() => _errorMessage = null"></button>
+        </div>
+    }
+
+    @if (_submitted)
+    {
+        <div class="card border-success">
+            <div class="card-body text-center py-5">
+                <div class="text-success mb-3" style="font-size: 3rem;">&#10003;</div>
+                <h2 class="card-title text-success">Application Submitted!</h2>
+                <p class="card-text fs-5">Your application has been received.</p>
+                <p class="card-text"><strong>Application ID:</strong> @_applicationId</p>
+            </div>
+        </div>
+    }
+    else
+    {
+        @switch (_currentStep)
+        {
+            case 0:
+                <StepPersonalInfo FullName="@_fullName" Email="@_email" Phone="@_phone" Address="@_address"
+                                  FullNameChanged="v => _fullName = v" EmailChanged="v => _email = v"
+                                  PhoneChanged="v => _phone = v" AddressChanged="v => _address = v" />
+                break;
+            case 1:
+                <StepWorkHistory Entries="_workEntries" />
+                break;
+            case 2:
+                <StepReferences References="_references" />
+                break;
+            case 3:
+                <StepCoverLetter Text="@_coverLetter" TextChanged="v => _coverLetter = v" />
+                break;
+            case 4:
+                <StepReview FullName="@_fullName" Email="@_email" Phone="@_phone" Address="@_address"
+                            WorkEntries="_workEntries" References="_references" CoverLetter="@_coverLetter"
+                            OnEditSection="GoToStep" />
+                break;
+        }
+
+        <div class="d-flex justify-content-between mt-4">
+            @if (_currentStep > 0)
+            {
+                <button class="btn btn-outline-secondary" @onclick="PreviousStep" disabled="@_isProcessing">
+                    &larr; Back
+                </button>
+            }
+            else
+            {
+                <div></div>
+            }
+
+            @if (_currentStep < StepCount - 1)
+            {
+                <button class="btn btn-primary" @onclick="NextStep" disabled="@_isProcessing">
+                    @if (_isProcessing)
+                    {
+                        <span class="spinner-border spinner-border-sm me-1" role="status"></span>
+                    }
+                    Next &rarr;
+                </button>
+            }
+            else
+            {
+                <button class="btn btn-success" @onclick="SubmitApplication" disabled="@_isProcessing">
+                    @if (_isProcessing)
+                    {
+                        <span class="spinner-border spinner-border-sm me-1" role="status"></span>
+                    }
+                    Submit Application
+                </button>
+            }
+        </div>
+    }
+</div>
+
+@code {
+    private const int StepCount = 5;
+
+    private readonly string[] _stepLabels =
+    [
+        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
+    ];
+
+    private int _currentStep;
+    private int _highestCompletedStep;
+    private bool _isProcessing;
+    private bool _submitted;
+    private int? _applicationId;
+    private string? _errorMessage;
+
+    // Step 1
+    private string _fullName = "";
+    private string _email = "";
+    private string _phone = "";
+    private string _address = "";
+
+    // Step 2
+    private List<WorkEntryModel> _workEntries = [new()];
+
+    // Step 3
+    private List<ReferenceModel> _references = [new(), new()];
+
+    // Step 4
+    private string _coverLetter = "";
+
+    private void GoToStep(int step)
+    {
+        if (step <= _highestCompletedStep)
+        {
+            _currentStep = step;
+            _errorMessage = null;
+        }
+    }
+
+    private async Task NextStep()
+    {
+        _errorMessage = null;
+        _isProcessing = true;
+
+        try
+        {
+            if (!await ValidateCurrentStep())
+                return;
+
+            if (_currentStep >= _highestCompletedStep)
+                _highestCompletedStep = _currentStep + 1;
+
+            _currentStep++;
+        }
+        finally
+        {
+            _isProcessing = false;
+        }
+    }
+
+    private void PreviousStep()
+    {
+        if (_currentStep > 0)
+        {
+            _currentStep--;
+            _errorMessage = null;
+        }
+    }
+
+    private async Task<bool> ValidateCurrentStep()
+    {
+        switch (_currentStep)
+        {
+            case 0:
+                if (string.IsNullOrWhiteSpace(_fullName))
+                    { _errorMessage = "Full name is required."; return false; }
+                if (string.IsNullOrWhiteSpace(_email))
+                    { _errorMessage = "Email is required."; return false; }
+                if (string.IsNullOrWhiteSpace(_phone))
+                    { _errorMessage = "Phone number is required."; return false; }
+                if (string.IsNullOrWhiteSpace(_address))
+                    { _errorMessage = "Address is required."; return false; }
+                if (!await ApplicationService.ValidateEmailAsync(_email))
+                    { _errorMessage = "Please enter a valid email address."; return false; }
+                break;
+
+            case 1:
+                foreach (var entry in _workEntries)
+                {
+                    if (string.IsNullOrWhiteSpace(entry.Company))
+                        { _errorMessage = "Company name is required for all entries."; return false; }
+                    if (string.IsNullOrWhiteSpace(entry.Title))
+                        { _errorMessage = "Job title is required for all entries."; return false; }
+                    if (entry.StartDate == default)
+                        { _errorMessage = "Start date is required for all entries."; return false; }
+                }
+                break;
+
+            case 2:
+                foreach (var r in _references)
+                {
+                    if (string.IsNullOrWhiteSpace(r.Name))
+                        { _errorMessage = "Name is required for all references."; return false; }
+                    if (string.IsNullOrWhiteSpace(r.Relationship))
+                        { _errorMessage = "Relationship is required for all references."; return false; }
+                    if (string.IsNullOrWhiteSpace(r.Email))
+                        { _errorMessage = "Email is required for all references."; return false; }
+                    if (string.IsNullOrWhiteSpace(r.Phone))
+                        { _errorMessage = "Phone is required for all references."; return false; }
+                }
+                break;
+
+            case 3:
+                if (string.IsNullOrWhiteSpace(_coverLetter))
+                    { _errorMessage = "Cover letter is required."; return false; }
+                break;
+        }
+
+        return true;
+    }
+
+    private async Task SubmitApplication()
+    {
+        _errorMessage = null;
+        _isProcessing = true;
+
+        try
+        {
+            var application = new JobApplication(
+                new PersonalInfo(_fullName, _email, _phone, _address),
+                new WorkHistory(_workEntries.Select(e =>
+                    new WorkEntry(e.Company, e.Title, e.StartDate, e.IsCurrent ? null : e.EndDate, e.Description)).ToList()),
+                _references.Select(r =>
+                    new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList(),
+                _coverLetter
+            );
+
+            _applicationId = await ApplicationService.SubmitApplicationAsync(application);
+            _submitted = true;
+            _highestCompletedStep = StepCount;
+        }
+        catch (Exception ex)
+        {
+            _errorMessage = $"Submission failed: {ex.Message}";
+        }
+        finally
+        {
+            _isProcessing = false;
+        }
+    }
+
+    public class WorkEntryModel
+    {
+        public string Company { get; set; } = "";
+        public string Title { get; set; } = "";
+        public DateTime StartDate { get; set; }
+        public DateTime? EndDate { get; set; }
+        public bool IsCurrent { get; set; }
+        public string Description { get; set; } = "";
+    }
+
+    public class ReferenceModel
+    {
+        public string Name { get; set; } = "";
+        public string Relationship { get; set; } = "";
+        public string Email { get; set; } = "";
+        public string Phone { get; set; } = "";
+    }
+}
+

