.step-indicator {
    --step-active: #0d6efd;
    --step-completed: #198754;
    --step-dimmed: #adb5bd;
}

.step-progress-track {
    position: absolute;
    top: 18px;
    left: 10%;
    right: 10%;
    height: 3px;
    background-color: var(--step-dimmed);
    z-index: 0;
}

.step-progress-fill {
    height: 100%;
    background-color: var(--step-completed);
    transition: width 0.3s ease;
}

.step-item {
    position: relative;
    z-index: 1;
    flex: 1;
}

.step-circle {
    width: 38px;
    height: 38px;
    border-radius: 50%;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.9rem;
    border: 3px solid var(--step-dimmed);
    background-color: #fff;
    color: var(--step-dimmed);
    transition: all 0.2s ease;
}

.step-item.active .step-circle {
    border-color: var(--step-active);
    background-color: var(--step-active);
    color: #fff;
}

.step-item.completed .step-circle {
    border-color: var(--step-completed);
    background-color: var(--step-completed);
    color: #fff;
}

.step-item.dimmed .step-label {
    color: var(--step-dimmed);
}

.step-item.active .step-label {
    color: var(--step-active);
    font-weight: 600;
}

.step-item.completed .step-label {
    color: var(--step-completed);
}

.step-item.completed:hover .step-circle {
    transform: scale(1.1);
}

