@using static sv_03d58a53aa5741ac93a619a38dfa9fca.Components.Pages.Apply

<h3>Work History</h3>

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    var entry = Entries[index];

    <div class="card p-4 mb-3">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <h5 class="mb-0">Position @(index + 1)</h5>
            @if (Entries.Count > 1)
            {
                <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveEntry(index)">Remove</button>
            }
        </div>

        <div class="row mb-3">
            <div class="col-md-6">
                <label class="form-label">Company <span class="text-danger">*</span></label>
                <input type="text" class="form-control" value="@entry.Company"
                       @oninput="e => entry.Company = e.Value?.ToString() ?? """ />
            </div>
            <div class="col-md-6">
                <label class="form-label">Job Title <span class="text-danger">*</span></label>
                <input type="text" class="form-control" value="@entry.Title"
                       @oninput="e => entry.Title = e.Value?.ToString() ?? """ />
            </div>
        </div>

        <div class="row mb-3">
            <div class="col-md-4">
                <label class="form-label">Start Date <span class="text-danger">*</span></label>
                <input type="date" class="form-control" value="@(entry.StartDate == default ? "" : entry.StartDate.ToString("yyyy-MM-dd"))"
                       @onchange="e => { if (DateTime.TryParse(e.Value?.ToString(), out var d)) entry.StartDate = d; }" />
            </div>
            <div class="col-md-4">
                <label class="form-label">End Date</label>
                <input type="date" class="form-control" value="@(entry.EndDate?.ToString("yyyy-MM-dd") ?? "")"
                       disabled="@entry.IsCurrent"
                       @onchange="e => { if (DateTime.TryParse(e.Value?.ToString(), out var d)) entry.EndDate = d; }" />
            </div>
            <div class="col-md-4 d-flex align-items-end mb-1">
                <div class="form-check">
                    <input class="form-check-input" type="checkbox" checked="@entry.IsCurrent"
                           @onchange="e => { entry.IsCurrent = (bool)(e.Value ?? false); if (entry.IsCurrent) entry.EndDate = null; }" />
                    <label class="form-check-label">Currently working here</label>
                </div>
            </div>
        </div>

        <div class="mb-3">
            <label class="form-label">Description</label>
            <textarea class="form-control" rows="3" value="@entry.Description"
                      @oninput="e => entry.Description = e.Value?.ToString() ?? """></textarea>
        </div>
    </div>
}

<button class="btn btn-outline-primary" @onclick="AddEntry">
    + Add Another Position
</button>

@code {
    [Parameter] public List<WorkEntryModel> Entries { get; set; } = [];

    private void AddEntry() => Entries.Add(new WorkEntryModel());

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
            Entries.RemoveAt(index);
    }
}

@using static sv_03d58a53aa5741ac93a619a38dfa9fca.Components.Pages.Apply

<h3>References</h3>

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    var reference = References[index];

    <div class="card p-4 mb-3">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <h5 class="mb-0">Reference @(index + 1)</h5>
            @if (References.Count > 2)
            {
                <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveReference(index)">Remove</button>
            }
        </div>

        <div class="row mb-3">
            <div class="col-md-6">
                <label class="form-label">Name <span class="text-danger">*</span></label>
                <input type="text" class="form-control" value="@reference.Name"
                       @oninput="e => reference.Name = e.Value?.ToString() ?? """ />
            </div>
            <div class="col-md-6">
                <label class="form-label">Relationship <span class="text-danger">*</span></label>
                <input type="text" class="form-control" value="@reference.Relationship"
                       @oninput="e => reference.Relationship = e.Value?.ToString() ?? """ placeholder="e.g., Former Manager" />
            </div>
        </div>

        <div class="row mb-3">
            <div class="col-md-6">
                <label class="form-label">Email <span class="text-danger">*</span></label>
                <input type="email" class="form-control" value="@reference.Email"
                       @oninput="e => reference.Email = e.Value?.ToString() ?? """ />
            </div>
            <div class="col-md-6">
                <label class="form-label">Phone <span class="text-danger">*</span></label>
                <input type="tel" class="form-control" value="@reference.Phone"
                       @oninput="e => reference.Phone = e.Value?.ToString() ?? """ />
            </div>
        </div>
    </div>
}

@if (References.Count < 3)
{
    <button class="btn btn-outline-primary" @onclick="AddReference">
        + Add Reference
    </button>
}

@code {
    [Parameter] public List<ReferenceModel> References { get; set; } = [];

    private void AddReference()
    {
        if (References.Count < 3)
            References.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
            References.RemoveAt(index);
    }
}

